import requests
from dataclasses import dataclass, field
from datetime import datetime

@dataclass
class PatientContext:
    patient_id: str
    name: str
    age_years: int
    sex: str
    active_conditions: list[dict]    # [{code, display, onset_date}]
    active_medications: list[dict]   # [{rxnorm_code, display, dose, route}]
    recent_labs: list[dict]          # [{loinc_code, display, value, unit, date}]
    clinical_notes: list[str]        # most recent 3 notes
    accessed_at: str = field(default_factory=lambda: datetime.utcnow().isoformat())


class FHIRPatientLoader:
    """Fetches and normalizes a patient context from a FHIR R4 endpoint."""

    def __init__(self, base_url: str, access_token: str):
        self.base = base_url.rstrip("/")
        self.session = requests.Session()
        self.session.headers.update({
            "Authorization": f"Bearer {access_token}",
            "Accept": "application/fhir+json",
        })

    def _get(self, path: str, params: dict | None = None) -> dict:
        resp = self.session.get(f"{self.base}/{path}", params=params, timeout=10)
        resp.raise_for_status()
        return resp.json()

    def load(self, patient_id: str) -> PatientContext:
        pt = self._get(f"Patient/{patient_id}")
        name_obj = pt.get("name", [{}])[0]
        name = " ".join(name_obj.get("given", [])) + " " + name_obj.get("family", "")
        birth = pt.get("birthDate", "")
        age = (datetime.now().year - int(birth[:4])) if birth else 0
        sex = pt.get("gender", "unknown")

        # Active conditions
        cond_bundle = self._get("Condition", {
            "patient": patient_id,
            "clinical-status": "active",
            "_count": 20,
        })
        conditions = [
            {
                "code": e["resource"]["code"]["coding"][0]["code"],
                "display": e["resource"]["code"]["coding"][0]["display"],
                "onset_date": e["resource"].get("onsetDateTime", ""),
            }
            for e in cond_bundle.get("entry", [])
        ]

        # Active medications
        med_bundle = self._get("MedicationRequest", {
            "patient": patient_id,
            "status": "active",
            "_count": 20,
        })
        medications = [
            {
                "rxnorm_code": (
                    e["resource"]["medicationCodeableConcept"]["coding"][0]["code"]
                    if "medicationCodeableConcept" in e["resource"] else ""
                ),
                "display": (
                    e["resource"]["medicationCodeableConcept"]["coding"][0]["display"]
                    if "medicationCodeableConcept" in e["resource"] else ""
                ),
                "dose": (
                    e["resource"].get("dosageInstruction", [{}])[0]
                    .get("doseAndRate", [{}])[0]
                    .get("doseQuantity", {}).get("value", "")
                ),
                "route": (
                    e["resource"].get("dosageInstruction", [{}])[0]
                    .get("route", {}).get("text", "")
                ),
            }
            for e in med_bundle.get("entry", [])
        ]

        # Recent labs (last 10 observations)
        obs_bundle = self._get("Observation", {
            "patient": patient_id,
            "category": "laboratory",
            "_sort": "-date",
            "_count": 10,
        })
        labs = [
            {
                "loinc_code": e["resource"]["code"]["coding"][0]["code"],
                "display": e["resource"]["code"]["coding"][0]["display"],
                "value": e["resource"].get("valueQuantity", {}).get("value", ""),
                "unit": e["resource"].get("valueQuantity", {}).get("unit", ""),
                "date": e["resource"].get("effectiveDateTime", ""),
            }
            for e in obs_bundle.get("entry", [])
        ]

        return PatientContext(
            patient_id=patient_id,
            name=name.strip(),
            age_years=age,
            sex=sex,
            active_conditions=conditions,
            active_medications=medications,
            recent_labs=labs,
            clinical_notes=[],   # fetched separately from DocumentReference
        )
